import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"공지","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/news.md","filePath":"work-manage/news.md","lastUpdated":1783341447000}'),i={name:"work-manage/news.md"};function o(s,a,n,h,d,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="공지" tabindex="-1">공지 <a class="header-anchor" href="#공지" aria-label="Permalink to &quot;공지&quot;">​</a></h1><p>업무 관리 시스템의 전사 공지 및 프로젝트별 주요 소식을 공유하고 관리하는 <strong>공지</strong> 페이지에 대한 사용자 가이드입니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>공지 화면은 중요한 정보나 변경 사항을 팀원들과 공유하는 게시판 역할을 합니다. 시스템 전체 공지와 개별 프로젝트별 뉴스를 구분하여 효율적인 소통을 지원합니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📢-전역-공지-vs-프로젝트-공지" tabindex="-1">📢 전역 공지 vs 프로젝트 공지 <a class="header-anchor" href="#📢-전역-공지-vs-프로젝트-공지" aria-label="Permalink to &quot;📢 전역 공지 vs 프로젝트 공지&quot;">​</a></h3><ul><li><strong>전역 공지</strong>: 시스템 메인 메뉴의 [공지]를 통해 접근하며, 회사 전체 구성원에게 전달되는 통합 소식을 확인합니다.</li><li><strong>프로젝트 공지</strong>: 특정 프로젝트 내의 [공지] 탭을 통해 접근하며, 해당 프로젝트 참여자들 간의 세부적인 협업 소식과 뉴스만 모아서 보여줍니다.</li></ul><h3 id="📝-새-공지-작성-및-편집" tabindex="-1">📝 새 공지 작성 및 편집 <a class="header-anchor" href="#📝-새-공지-작성-및-편집" aria-label="Permalink to &quot;📝 새 공지 작성 및 편집&quot;">​</a></h3><p>공지 관리 권한이 있는 사용자는 자유롭게 정보를 등록하고 관리할 수 있습니다.</p><ul><li><strong>새 공지 작성</strong> (<i class="mdi mdi-plus-circle text-success"></i>): 우측 상단의 버튼을 클릭하여 제목, 내용, 관련 파일을 첨부해 새 소식을 게시합니다.</li><li><strong>내용 편집</strong> (<i class="mdi mdi-pencil text-amber"></i>): 이미 게시된 공지의 내용을 수정하거나 보완할 수 있습니다.</li><li><strong>공지 삭제</strong> (<i class="mdi mdi-trash-can-outline text-grey"></i>): 더 이상 유효하지 않은 공지를 삭제 처리합니다.</li></ul><h3 id="📎-파일-첨부-및-마크다운-지원" tabindex="-1">📎 파일 첨부 및 마크다운 지원 <a class="header-anchor" href="#📎-파일-첨부-및-마크다운-지원" aria-label="Permalink to &quot;📎 파일 첨부 및 마크다운 지원&quot;">​</a></h3><ul><li><strong>마크다운(Markdown)</strong>: 서식이 있는 텍스트를 지원하여 강조, 리스트, 표 등을 사용해 공지 내용을 가독성 있게 작성할 수 있습니다.</li><li><strong>멀티 파일 첨부</strong>: 이미지, 문서 등 공지와 관련된 여러 개의 파일을 한 번에 업로드하고 공유할 수 있습니다.</li></ul><h3 id="⭐-지켜보기-watch" tabindex="-1">⭐ 지켜보기 (Watch) <a class="header-anchor" href="#⭐-지켜보기-watch" aria-label="Permalink to &quot;⭐ 지켜보기 (Watch)&quot;">​</a></h3><ul><li>특정 프로젝트의 공지 활동에 대해 &#39;지켜보기&#39;를 설정하여 관심 있는 소식의 변화를 추적할 수 있습니다.</li></ul><h2 id="_3-이용-팁" tabindex="-1">3. 이용 팁 <a class="header-anchor" href="#_3-이용-팁" aria-label="Permalink to &quot;3. 이용 팁&quot;">​</a></h2><ul><li><strong>필터링된 소식</strong>: 프로젝트 내 공지에서는 상단의 브레드크럼(예: 공지 » 보기)을 활용해 목록과 상세 화면을 빠르게 오갈 수 있습니다.</li><li><strong>시인성</strong>: 중요도가 높은 소식은 제목을 명확하게 작성하고 마크다운 문법을 활용해 핵심 내용을 강조하는 것을 추천합니다.</li><li><strong>첨부파일 관리</strong>: 공지 상세 보기 화면에서 첨부된 파일들을 직접 다운로드하거나 내용을 미리 확인할 수 있습니다.</li></ul>',16)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
